}

public final class CustomProcessor extends org.machanism.machai.gw.processor.AIFileProcessor {
  public CustomProcessor(java.io.File rootDir, org.machanism.macha.core.commons.configurator.Configurator configurator, java.lang.String genai) { super(rootDir, configurator, genai); }
